 86→            </div>
 87→        )
 88→    }
 89→
 90→    return(
 91→        <>
 92→        <div className='profile-postcards-parent-container'>
 93→            <div className="postcards-header-row">
 94→                <h2 className="postcards-heading">
 95→                    Posts <span className="postcards-count">({journals.length})</span>
 96→                </h2>
 97→                <div className="postcards-header-actions">
 98→                    <button
 99→                        className={`postcards-view-toggle-btn ${viewMode === 'grid' ? 'is-active' : ''}`}
100→                        onClick={handleToggleView}
101→                        title={viewMode === 'grid' ? 'Switch to list' : 'Switch to grid'}
102→                    >
103→                        {viewMode === 'grid' ? (
104→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-520v-320h320v320H120Zm0 400v-320h320v320H120Zm400-400v-320h320v320H520Zm0 400v-320h320v320H520Z"/></svg>
105→                        ) : (
106→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-200v-560h720v560H120Z"/></svg>
107→                        )}
108→                    </button>
109→                </div>
110→            </div>
111→
112→            {viewMode === 'grid' ? (
113→                <div className="postcards-grid-view">
114→                    {journals.map((journal) => {
115→                        const previewText = journal?.preview_text || '';
116→                        const thumbnail = journal?.thumbnail_url || null;
117→                        return (
118→                            <motion.div
119→                                key={journal.id}
120→                                className="postcards-grid-item"
121→                                initial={{ opacity: 0, scale: 0.95 }}
122→                                animate={{ opacity: 1, scale: 1 }}
123→                                transition={{ duration: 0.25, ease: 'easeOut' }}
124→                                onClick={(e) => viewContent(e, null, '', journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
125→                            >
126→                                {thumbnail ? (
127→                                    <div className="postcards-grid-img-wrap">
128→                                        <img className="postcards-grid-thumb" src={thumbnail} alt={journal?.title ? `${journal.title} cover image` : "Post cover image"} loading="lazy" onError={handleImageFallback} />
129→                                    </div>
130→                                ) : null}
131→                                <div className="postcards-grid-body">
132→                                    <h3 className="postcards-grid-title">{journal.title.length > 32 ? `${journal.title.substring(0, 32)}...` : journal.title}</h3>
133→                                    {previewText && (
