135→                                    )}
136→                                </div>
137→                            </motion.div>
138→                        );
139→                    })}
140→                </div>
141→            ) : (
142→            <div className="postcards-list-view">
143→            {journals.map((journal, index) => {
144→                const previewText = journal?.preview_text || '';
145→                const thumbnail = journal?.thumbnail_url || null;
146→                const badgeClass = journal.users.badge === 'legend' ? 'avatar-ring-legend' : journal.users.badge === 'og' ? 'avatar-ring-og' : '';
147→
148→                return(
149→                    <motion.div
150→                        key={journal.id || index}
151→                        className="profile-postcards"
152→                        initial={{opacity: 0, y: 12}}
153→                        animate={{opacity: 1, y: 0}}
154→                        transition={{duration: 0.3, ease: 'easeOut'}}
155→                    >
156→                        {thumbnail && (
157→                            <img
158→                                className="card-image-banner"
159→                                src={thumbnail}
160→                                alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
161→                                loading="lazy"
162→                                onError={handleImageFallback}
163→                                onClick={(e) => viewContent(e, null, '', journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
164→                            />
165→                        )}
166→
167→                        <div className='user-profile-card-content'>
168→                            <div onClick={(e) => viewContent(e, null, '', journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)} className="content-container">
169→                                <div className='feed-text-content-container'>
170→                                    <div className='feed-title-content'>
171→                                        <h2 className="feed-title-profile-page">{journal.title.length > 55 ? `${journal.title.substring(0, 55)}...` : journal.title}</h2>
172→                                    </div>
173→                                    <p className="feed-text-content-profile-page">{previewText}</p>
174→                                </div>
175→                            </div>
176→
177→                            <div className="card-icons-container">
178→                                <div className='user-info-child-container'>
179→                                    <div className={`user-avatar-container ${badgeClass}`}>
180→                                        <img src={journal.users.image_url || '/assets/profile.jpg'} alt="user-profile" loading='lazy' className="user-info-avatar"/>
181→                                    </div>
182→                                    <div className="user-name-container">
183→                                        <p className="user-newsfeed-name-profile-page">{journal.users.name}</p>
184→                                        <VerifiedBadge badge={journal.users.badge} size={14} />
185→                                    </div>
186→                                    <div className="name-info-separator">•</div>
187→                                    <p className="user-post-date">{new Date(journal.created_at).toLocaleDateString('en-US', {
188→                                        month: 'long',
189→                                        day: 'numeric',
190→                                        year: 'numeric'
191→                                    })}</p>
192→
193→                                    <div className="user-post-settings">
194→                                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
195→                                    </div>
196→                                </div>
197→                            </div>
198→                        </div>
199→                    </motion.div>
200→                )
201→            })}
202→            </div>
203→            )}
204→
205→            <div ref={ref} className='in-view-container'>
206→                {isFetchingNextPage && (
207→                    <MoonLoader size={20} color="var(--loader-color)" loading={isFetchingNextPage}/>
208→                )}
209→            </div>
210→
211→        </div>
212→        </>
213→    )
214→}
